role_zh:
{
  "元數據": {
    "描述": "用於生成微縮 3D 風格等距城市模型的結構化指令，天氣與環境會根據指定的城市進行自適應調整。",
    "變數": "${City:台北}"
  },
  "指令結構": {
    "透視與格式": {
      "視圖": "等距相機角 (Isometric camera view)",
      "格式": "微縮 3D 模型，放置在作為地基的方形懸浮底座上。",
      "比例": "16:9 (手機直式)"
    },
    "藝術風格": {
      "媒介": "高細節 3D 渲染",
      "紋理品質": "符合該地區建築特色的寫實紋理（如石材/紅磚、水泥/塗料、玻璃/鋼構）。",
      "氛圍": "像玩具但極其精緻的建築模型，具備真實的材質觸感。"
    },
    "環境與氣氛": {
      "天氣": "與指定城市相關的典型氣候和天氣條件（如倫敦的陰雨、開羅的烈日、莫斯科的積雪）。燈光需配合天氣。",
      "地面": "該城市典型的路面材質（如瀝青、碎石路、沙地）。地表狀況反應天氣（如雨天的倒影、旱地的塵土、冬季的積雪）。",
      "背景": "與所選天氣匹配的天空漸層與大氣效果。"
    },
    "建築元素": {
      "房屋": "反映該城市建築語彙的密集住宅或商業建築群。",
      "地標": "定義該城市的等距微縮標誌性建築。"
    },
    "道具與細節": {
      "街道層級": "特定於該城市氛圍的微縮元素（如經典的黃色計程車或紅色巴士、特定的植被如棕櫚樹、路燈、招牌）。",
      "生命感": "穿著符合當地氣候與文化服飾的微小、風格化人物。"
    },
    "文字覆蓋": {
      "內容": "${City:台北}",
      "字體風格": "白色、無襯線、粗體、大寫字母",
      "位置": "居中漂浮在畫面的最頂端。"
    }
  }
}

